async function getGreeting(name: string): Promise<string> {
  return `Hello, ${name}!`;
}

async function getDouble(n: number): Promise<number> {
  return n * 2;
}

async function main(): Promise<void> {
  const msg = await getGreeting("Alice");  // string, not Promise<string>
  const val = await getDouble(21);          // number
  console.log(msg);
  console.log(`Double: ${val}`);
}

main();

async function delay(ms: number): Promise<void> {
  return new Promise(resolve => setTimeout(resolve, ms));
}

async function fetchValue(id: number): Promise<{ id: number; value: string }> {
  await delay(0);
  const data = [{ id: 1, value: "alpha" }, { id: 2, value: "beta" }];
  const found = data.find(d => d.id === id);
  if (!found) throw new Error(`Not found: ${id}`);
  return found;
}

async function main() {
  const result = await fetchValue(1);  // { id: number; value: string }
  console.log(`ID: ${result.id}`);
  console.log(`Value: ${result.value}`);
}

main();

async function fetchUser(id: number): Promise<string> {
  if (id <= 0)   throw new Error("ID must be positive");
  if (id > 100)  throw new Error("User not found");
  return `User #${id}`;
}

async function main() {
  const ids = [1, -1, 50, 200];
  for (const id of ids) {
    try {
      const user = await fetchUser(id);
      console.log(`✓ ${user}`);
    } catch (error) {
      // error is unknown — must narrow
      const msg = error instanceof Error ? error.message : String(error);
      console.log(`✗ ${msg}`);
    }
  }
}

main();

async function getUsername(id: number): Promise<string> {
  const names = ["Alice", "Bob", "Carol"];
  return names[id - 1] ?? "Unknown";
}

async function getScore(id: number): Promise<number> {
  const scores = [2850, 1920, 3100];
  return scores[id - 1] ?? 0;
}

async function getUserProfile(id: number): Promise<void> {
  // Run both in parallel — not sequentially
  const [name, score]: [string, number] = await Promise.all([
    getUsername(id),
    getScore(id),
  ]);
  console.log(`${name}: ${score} XP`);
}

async function main() {
  await getUserProfile(1);
  await getUserProfile(2);
  await getUserProfile(3);
}

main();

async function loadMetric(name: string, shouldFail: boolean): Promise<number> {
  if (shouldFail) throw new Error(`${name} unavailable`);
  const data: Record<string, number> = { users: 1247, revenue: 84320 };
  return data[name] ?? 0;
}

async function main() {
  const metrics = ["users", "revenue", "churn"];
  const failures = new Set(["churn"]);

  const results = await Promise.allSettled(
    metrics.map(m => loadMetric(m, failures.has(m)))
  );

  for (let i = 0; i < results.length; i++) {
    const r = results[i];
    const name = metrics[i];
    if (r.status === "fulfilled") {
      console.log(`✓ ${name}: ${r.value}`);
    } else {
      console.log(`✗ ${name}: ${r.reason.message}`);
    }
  }
}

main();

async function* generateIds(count: number): AsyncGenerator<number> {
  for (let i = 1; i <= count; i++) {
    yield i;
  }
}

async function* fetchPage(page: number): AsyncGenerator<{ id: number; name: string }[]> {
  const pages = [
    [{ id: 1, name: "Alice" }, { id: 2, name: "Bob" }],
    [{ id: 3, name: "Carol" }, { id: 4, name: "Dan" }],
    [{ id: 5, name: "Eve" }],
  ];
  if (page < pages.length) yield pages[page];
}

async function main() {
  const ids: number[] = [];
  for await (const id of generateIds(5)) {
    ids.push(id);
  }
  console.log(`IDs: ${ids.join(", ")}`);

  for (let p = 0; p < 3; p++) {
    for await (const users of fetchPage(p)) {
      console.log(`Page ${p+1}: ${users.map(u => u.name).join(", ")}`);
    }
  }
}

main();

type AsyncCallback<T, E = Error> = {
  onSuccess: (value: T) => void;
  onError:   (error: E) => void;
};

async function withCallback<T>(
  operation: () => Promise<T>,
  callbacks: AsyncCallback<T>
): Promise<void> {
  try {
    const result = await operation();
    callbacks.onSuccess(result);
  } catch (err) {
    callbacks.onError(err instanceof Error ? err : new Error(String(err)));
  }
}

