class UserRepo {
  private users: { id: number; name: string; plan: string }[] = [
    { id: 1, name: "Alice", plan: "pro" },
    { id: 2, name: "Bob",   plan: "free" },
    { id: 3, name: "Carol", plan: "pro" },
  ];

  async findById(id: number): Promise<typeof this.users[number] | null> {
    await Promise.resolve();  // simulate async
    return this.users.find(u => u.id === id) ?? null;
  }

  async findByPlan(plan: string): Promise<typeof this.users> {
    await Promise.resolve();
    return this.users.filter(u => u.plan === plan);
  }

  async count(): Promise<number> {
    return this.users.length;
  }
}

async function main() {
  const repo = new UserRepo();
  const alice = await repo.findById(1);
  const proUsers = await repo.findByPlan("pro");
  const total = await repo.count();

  console.log(`Alice: ${alice?.name} (${alice?.plan})`);
  console.log(`Pro users: ${proUsers.map(u => u.name).join(", ")}`);
  console.log(`Total: ${total}`);
}

main();

async function fetchWithTimeout<T>(
  operation: (signal: AbortSignal) => Promise<T>,
  timeoutMs: number
): Promise<T> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), timeoutMs);

  try {
    return await operation(controller.signal);
  } catch (err) {
    if (controller.signal.aborted) {
      throw new Error(`Operation timed out after ${timeoutMs}ms`);
    }
    throw err;
  } finally {
    clearTimeout(timeout);
  }
}

async function slowOperation(signal: AbortSignal): Promise<string> {
  return new Promise((resolve, reject) => {
    const t = setTimeout(() => resolve("Done"), 0);
    signal.addEventListener("abort", () => {
      clearTimeout(t);
      reject(new Error("Aborted"));
    });
  });
}

async function main() {
  try {
    const result = await fetchWithTimeout(slowOperation, 5000);
    console.log(`Result: ${result}`);
  } catch (err) {
    console.log(`Error: ${(err as Error).message}`);
  }
}

main();

async function* streamNumbers(
  from: number,
  to: number,
  batchSize = 2
): AsyncGenerator<number[], void, undefined> {
  for (let i = from; i <= to; i += batchSize) {
    const batch = Array.from(
      { length: Math.min(batchSize, to - i + 1) },
      (_, j) => i + j
    );
    yield batch;
  }
}

async function processStream(): Promise<void> {
  let total = 0;
  let batchCount = 0;

  for await (const batch of streamNumbers(1, 10, 3)) {
    const sum = batch.reduce((a, b) => a + b, 0);
    total += sum;
    batchCount++;
    console.log(`Batch ${batchCount}: [${batch.join(",")}] sum=${sum}`);
  }

  console.log(`Total: ${total}`);
}

processStream();

type Callback<T> = (error: Error | null, result: T | null) => void;

function promisify<T>(fn: (callback: Callback<T>) => void): () => Promise<T> {
  return () => new Promise<T>((resolve, reject) => {
    fn((error, result) => {
      if (error !== null) {
        reject(error);
      } else if (result !== null) {
        resolve(result);
      } else {
        reject(new Error("No result"));
      }
    });
  });
}

